<template><div class="page home"><section class="shop"><div class="logo">K</div><div><h1>Koshop 卖家中心</h1><p>今日经营概览</p></div></section><section class="core"><article v-for="x in core"><span>{{x[0]}}</span><b>{{x[1]}}</b><small>昨日 —</small></article></section><section class="todos"><button v-for="x in ['待付款','待发货','待售后','待评价']"><b>0</b><span>{{x}}</span></button></section><section class="card"><h2>快捷入口</h2><div class="entry"><button v-for="x in entries" @click="navigate(x[1])"><component :is="x[2]"/>{{x[0]}}</button></div></section></div></template><script setup lang="ts">import{onMounted,ref}from'vue';import{Package,ClipboardList,Wallet,MessageCircle,Settings}from'lucide-vue-next';import{navigate}from'../router';const core=ref<any[]>([['支付金额','—'],['访客数','—'],['支付子订单数','—']]);const entries:any[]=[['商品','/products',Package],['订单','/orders',ClipboardList],['财务','/finance',Wallet],['消息','/messages',MessageCircle],['设置','/settings',Settings]];onMounted(async()=>{try{const j=await(await fetch('/api/koshop-seller/dashboard')).json(),d=j.data?.data||j.data||{};core.value=[['支付金额',d.today_paid_amount??'—'],['访客数',d.today_visitors??'—'],['支付子订单数',d.today_orders??'—']]}catch{}})</script>
